3	const COMPONENT_BLOCK_PRICE = 60;
4	const COMPONENT_TYPES = ["rune", "moonstone"];
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
8	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	const HIGH_ENCHANTMENT_THRESHOLD = 8;
13	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
14	const DEDUCTIBLE = 100;
15	const CAP_MULTIPLIER = 2;
16	
17	const INSURANCE_VALUES: Record<string, number> = {
18	  sword: 1000,
19	  amulet: 600,
20	  staff: 800,
21	  potion: 400,
22	  rune: 250,
23	  moonstone: 250,
24	};
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	interface Item {
36	  type: string;
37	  cursed?: boolean;
38	  enchantment?: number;
39	}
40	
41	interface Customer {
42	  yearsWithMHPCO: number;
43	}
44	
45	interface Damage {
46	  itemType: string;
47	  amount: number;
48	}
49	
50	interface Step {
51	  op: string;
52	  items?: Item[];
53	  policy?: number;
54	  incident?: {
55	    cause: string;
56	    damages: Damage[];
57	  };
58	}
59	
60	interface Policy {
61	  items: Item[];
62	  insuranceSum: number;
63	  remainingCap: number;
64	}
65	
66	interface Scenario {
67	  customer: Customer;
68	  steps: Step[];
69	}
70	
71	const isComponent = (item: Item): boolean =>
72	  COMPONENT_TYPES.includes(item.type);
73	
74	const calculateComponentPremium = (type: string, count: number): number =>
75	  count === COMPONENT_BLOCK_SIZE
76	    ? COMPONENT_BLOCK_PRICE
77	    : count * (BASE_PREMIUMS[type] ?? 0);
78	
79	const calculateItemPremium = (item: Item): number => {
80	  const basePremium = BASE_PREMIUMS[item.type] ?? 0;
81	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
82	  const enchantmentSurcharge =
83	    (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD ? basePremium * ENCHANTMENT_SURCHARGE_RATE : 0;
84	  return basePremium + cursedSurcharge + enchantmentSurcharge;
85	};
